      <div className="hero-content">
        <span className="hero-tag">Seguimiento de vehículos</span>

        <h1>
          LOCALIZA TU FLOTA
          <br />
          Y TOMA CONTROL
          <br />
          EN TIEMPO REAL
        </h1>

