            Ver panel en vivo
          </a>
        </div>

        <div className="hero-proof">
          <div className="proof-box">
            <strong>24/7</strong>
            <span>Seguimiento continuo</span>
          </div>
          <div className="proof-box">
            <strong>En vivo</strong>
            <span>Ubicación inmediata</span>
          </div>
          <div className="proof-box">
            <strong>Alertas</strong>
            <span>Eventos clave</span>
          </div>
        </div>
      </div>
    </section>
  );
